161: /**
162:  * Provides the draining filter chains and the functionality to schedule listener destroy.
163:  */
164: class DrainingFilterChainsManager {
165: public:
166:   DrainingFilterChainsManager(ListenerImplPtr&& draining_listener,
167:                               uint64_t workers_pending_removal);
168:   uint64_t getDrainingListenerTag() const { return draining_listener_->listenerTag(); }
169:   const std::list<const Network::FilterChain*>& getDrainingFilterChains() const {
170:     return draining_filter_chains_;
171:   }
172:   ListenerImpl& getDrainingListener() const { return *draining_listener_; }
173:   uint64_t decWorkersPendingRemoval() { return --workers_pending_removal_; }
174: 
175:   // Schedule listener destroy.
176:   void startDrainSequence(std::chrono::seconds drain_time, Event::Dispatcher& dispatcher,
177:                           std::function<void()> completion) {
178:     drain_sequence_completion_ = completion;
179:     ASSERT(!drain_timer_);
180: 
181:     drain_timer_ = dispatcher.createTimer([this]() -> void { drain_sequence_completion_(); });
182:     drain_timer_->enableTimer(drain_time);
183:   }
184: 
185:   void addFilterChainToDrain(const Network::FilterChain& filter_chain) {
186:     draining_filter_chains_.push_back(&filter_chain);
187:   }
188: 
189:   uint32_t numDrainingFilterChains() const { return draining_filter_chains_.size(); }
190: 
191: private:
192:   ListenerImplPtr draining_listener_;
193:   std::list<const Network::FilterChain*> draining_filter_chains_;
194: 
195:   uint64_t workers_pending_removal_;
196:   Event::TimerPtr drain_timer_;
197:   std::function<void()> drain_sequence_completion_;
198: };
