174:   createConnectionHandler(Event::Dispatcher& dispatcher, absl::optional<uint32_t> worker_index,
175:                           OverloadManager& overload_manager,
176:                           OverloadManager& null_overload_manager) override {
177:     return std::make_unique<ConnectionHandlerImpl>(dispatcher, worker_index, overload_manager,
178:                                                    null_overload_manager);
